import sys
from collections import defaultdict

def main():
    s = sys.stdin.readline().strip()
    res = 0
    x_positions = [i for i, c in enumerate(s) if c == 'X']
    x_count = len(x_positions)
    underscore_positions = [i for i, c in enumerate(s) if c == '_']
    underscore_count = len(underscore_positions)

    def is_valid(candidate):
        if len(candidate) > 1 and candidate[0] == '0':
            return False
        return int(candidate) % 25 == 0

    x_values = range(10) if x_count > 0 else [None]
    for x_val in x_values:
        temp = list(s)
        if x_count > 0:
            for pos in x_positions:
                temp[pos] = str(x_val)
        modified_s = ''.join(temp)

        underscore_positions_in_modified = [i for i, c in enumerate(modified_s) if c == '_']
        underscore_count_in_modified = len(underscore_positions_in_modified)

        if underscore_count_in_modified == 0:
            if is_valid(modified_s):
                res += 1
        else:
            from itertools import product
            for digits in product('0123456789', repeat=underscore_count_in_modified):
                candidate = list(modified_s)
                for i, pos in enumerate(underscore_positions_in_modified):
                    candidate[pos] = digits[i]
                candidate_str = ''.join(candidate)
                if len(candidate_str) > 1 and candidate_str[0] == '0':
                    continue
                if is_valid(candidate_str):
                    res += 1
    print(res)

if __name__ == "__main__":
    main()
